    var multiSearchRequest = new MultiSearchRequest();

    foreach (var id in sparePartIds)
    {
        var searchRequest = new SearchRequest<SparePartEntity>
        {
            Query = new TermQuery { Field = "SparePartId", Value = id }
        };

        multiSearchRequest.Requests.Add(new SearchRequest<SparePartEntity>(index: "your_index_name", type: "your_type_name")
        {
            Query = searchRequest.Query
        });
    }

    var multiSearchResponse = _client.MultiSearch(multiSearchRequest);
    var queryResponses = multiSearchResponse.Responses;

    foreach (var sparePartId in sparePartIds)
    {
        var response = queryResponses.FirstOrDefault(r => r.OriginalRequest is SearchRequest<SparePartEntity> searchRequest && searchRequest.TypeName.Equals("your_type_name") && searchRequest.DocumentType.Equals(typeof(SparePartEntity)) && searchRequest.Id.Equals(sparePartId));

        if (response == null || response.Hits.Count == 0)
